# Let me find complementary column overlaps between all pairs of shapes.

def cols_complement(col_a, col_b):
    """Check if two columns perfectly complement (disjoint nonzero, union fills all)"""
    return all((a > 0) != (b > 0) for a, b in zip(col_a, col_b))

