# Let me write a cleaner, complete solve function.
import numpy as np
from collections import deque
from itertools import permutations, combinations

def solve(grid):
    grid = [list(row) for row in grid]
    H, W = len(grid), len(grid[0])

    # Find connected components
    def get_components(g):
        h, w = len(g), len(g[0])
        vis = set()
        comps = []
        for r in range(h):
            for c in range(w):
                if (r,c) not in vis and g[r][c] != 0:
                    color = g[r][c]
                    comp = []
                    q = deque([(r,c)])
                    vis.add((r,c))
                    while q:
                        cr, cc = q.popleft()
                        comp.append((cr,cc))
                        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                            nr, nc = cr+dr, cc+dc
                            if 0<=nr<h and 0<=nc<w and (nr,nc) not in vis and g[nr][nc]==color:
                                vis.add((nr,nc))
                                q.append((nr,nc))
                    comps.append((color, comp))
        return comps

    comps = get_components(grid)

    # Identify wall (largest component)
    wall_color, wall_cells = max(comps, key=lambda x: len(x[1]))
    wall_set = set(wall_cells)

    # Determine orientation
    wall_rows = set(r for r,c in wall_cells)
    wall_cols = set(c for r,c in wall_cells)
    row_span = max(wall_rows) - min(wall_rows) + 1
    col_span = max(wall_cols) - min(wall_cols) + 1

    transposed = False
    if row_span > col_span:
        grid = [list(row) for row in zip(*grid)]
        H, W = W, H
        transposed = True
        comps = get_components(grid)
        wall_color, wall_cells = max(comps, key=lambda x: len(x[1]))
        wall_set = set(wall_cells)
        wall_rows = set(r for r,c in wall_cells)

    wall_min_r = min(wall_rows)
    wall_max_r = max(wall_rows)

    # Get non-wall objects
    objects = []
    for color, comp in comps:
        if color != wall_color:
            min_r = min(r for r,c in comp)
            max_r = max(r for r,c in comp)
            min_c = min(c for r,c in comp)
            max_c = max(c for r,c in comp)
            shape = [[0]*(max_c-min_c+1) for _ in range(max_r-min_r+1)]
            for r,c in comp:
                shape[r-min_r][c-min_c] = color
            objects.append({'color': color, 'shape': shape, 'w': max_c-min_c+1, 'h': max_r-min_r+1})

    # Find holes in wall (0-cells within wall row range)
    hole_cells_set = set()
    for r in range(wall_min_r, wall_max_r+1):
        for c in range(W):
            if grid[r][c] == 0:
                hole_cells_set.add((r,c))

    # Connected components of holes
    visited = set()
    holes = []
    for cell in sorted(hole_cells_set):
        if cell not in visited:
            comp = []
            q = deque([cell])
            visited.add(cell)
            while q:
                r,c = q.popleft()
                comp.append((r,c))
                for dr,dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr,nc = r+dr, c+dc
                    if (nr,nc) in hole_cells_set and (nr,nc) not in visited:
                        visited.add((nr,nc))
                        q.append((nr,nc))
            min_r_h = min(r for r,c in comp)
            max_r_h = max(r for r,c in comp)
            side = None
            if min_r_h == wall_min_r:
                side = 'top'
            if max_r_h == wall_max_r:
                side = 'bottom' if side is None else 'both'
            if side is None:
                side = 'internal'
            holes.append({'cells': sorted(comp), 'side': side, 'min_r': min_r_h, 'max_r': max_r_h})

    # Helper functions
    def rows_complement(a, b):
        return all((av>0) != (bv>0) for av, bv in zip(a, b))

    def find_overlap(sa, sb):
        if not sa or not sb or len(sa[0]) != len(sb[0]):
            return 0
        for ov in range(min(len(sa), len(sb)), 0, -1):
            if all(rows_complement(sa[-ov+i], sb[i]) for i in range(ov)):
                return ov
        return 0

    # Group objects by width
    width_groups = {}
    for i, obj in enumerate(objects):
        w = obj['w']
        if w not in width_groups:
            width_groups[w] = []
        width_groups[w].append(i)

    # For each width group, find valid chains
    def find_all_chains(indices):
        """Find ways to partition indices into chains"""
        n = len(indices)
        shapes = [objects[i]['shape'] for i in indices]
        ov = [[0]*n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                if i != j:
                    ov[i][j] = find_overlap(shapes[i], shapes[j])

        # Try to find chains that cover all indices
        # Try single chain first
        for perm in permutations(range(n)):
            valid = all(ov[perm[k]][perm[k+1]] > 0 for k in range(n-1))
            if valid:
                return [[indices[p] for p in perm]]

        # Try splitting into 2 chains
        for size1 in range(1, n):
            for subset1 in combinations(range(n), size1):
                subset2 = tuple(i for i in range(n) if i not in subset1)
                for p1 in permutations(subset1):
                    if all(ov[p1[k]][p1[k+1]] > 0 for k in range(len(p1)-1)):
                        for p2 in permutations(subset2):
                            if all(ov[p2[k]][p2[k+1]] > 0 for k in range(len(p2)-1)):
                                return [[indices[p] for p in p1], [indices[p] for p in p2]]
        return []

    all_chains = []
    for w, indices in width_groups.items():
        chains = find_all_chains(indices)
        all_chains.extend(chains)

    # Match chains to holes
    def try_match_chain(chain, direction, hole):
        """
        Try to place chain through hole.
        direction: 'top' (entry from above, hole at top of wall) or 'bottom' (entry from below)
        Returns placement info or None.
        """
        shapes = [objects[i]['shape'] for i in chain]
        shape_w = len(shapes[0][0])

        if direction == 'top':
            # Entry shape is first, enters from above
            # Shape's bottom rows enter the hole
            entry_shape = shapes[0]

            # Hole profile by row
            hole_rows = {}
            for r,c in hole['cells']:
                if r not in hole_rows:
                    hole_rows[r] = set()
                hole_rows[r].add(c)

            # Surface = wall_min_r, deeper = higher row numbers
            sorted_hr = sorted(hole_rows.keys())
            depth = len(sorted_hr)
            if depth > len(entry_shape):
                return None

            # Entry rows: bottom 'depth' rows of entry shape
            # entry_rows[0] maps to sorted_hr[0] (surface/shallowest)
            # entry_rows[-1] maps to sorted_hr[-1] (deepest)
            # Wait: for top entry, the shape comes from above.
            # The shape's bottommost row goes to the deepest hole row.
            # The shape's next-to-bottom goes to the next shallower.
            # entry_rows are shape[-depth:] in order, but we map:
            # shape[-1] → sorted_hr[-1] (deepest)
            # shape[-2] → sorted_hr[-2]
            # shape[-depth] → sorted_hr[0] (shallowest/surface)

            entry_rows = entry_shape[-depth:]
            # entry_rows[0] = shape[-depth] → sorted_hr[0]
            # entry_rows[-1] = shape[-1] → sorted_hr[-1]
            # But wait: sorted_hr[0] is the shallowest (wall_min_r side).
            # For a top-opening hole: sorted_hr[0] = wall_min_r (surface),
            # sorted_hr[-1] = deeper into wall.
            # The shape's bottommost row (narrow) should go to the deepest.
            # So entry_rows should be reversed:
            # shape[-1] → sorted_hr[-1], shape[-2] → sorted_hr[-2], etc.
            # Actually entry_rows[i] → sorted_hr[i] works if we list both in order:
            # entry_rows[0] = shape[-depth] (wider) → sorted_hr[0] (surface, wider hole)
            # entry_rows[-1] = shape[-1] (narrower) → sorted_hr[-1] (deeper, narrower hole)
            # Yes, this is correct!

            for col_off in range(W - shape_w + 1):
                ok = True
                for d in range(depth):
                    sr = entry_rows[d]
                    hr = sorted_hr[d]
                    hcols = hole_rows[hr]
                    for sc in range(shape_w):
                        gc = col_off + sc
                        if sr[sc] != 0:
                            if gc not in hcols:
                                ok = False
                                break
                        else:
                            if gc in hcols:
                                ok = False
                                break
                    if not ok:
                        break
                if ok:
                    # Shape top row maps to grid row
                    # shape[-1] at sorted_hr[-1], so shape[0] at sorted_hr[-1] - (len(entry_shape)-1)
                    grid_row_top = sorted_hr[-1] - (len(entry_shape) - 1)
                    return {'direction': direction, 'col_off': col_off, 'grid_row_top': grid_row_top}
            return None

        else:  # bottom
            entry_shape = shapes[-1]

            hole_rows = {}
            for r,c in hole['cells']:
                if r not in hole_rows:
                    hole_rows[r] = set()
                hole_rows[r].add(c)

            # Surface = wall_max_r, deeper = lower row numbers
            sorted_hr = sorted(hole_rows.keys(), reverse=True)
            depth = len(sorted_hr)
            if depth > len(entry_shape):
                return None

            # Entry rows: top 'depth' rows of entry shape
            # entry_rows[0] = shape[0] (wider) → sorted_hr[0] = wall_max_r (surface)
            # entry_rows[-1] = shape[depth-1] (narrower) → sorted_hr[-1] (deeper)
            entry_rows = entry_shape[:depth]

            for col_off in range(W - shape_w + 1):
                ok = True
                for d in range(depth):
                    sr = entry_rows[d]
                    hr = sorted_hr[d]
                    hcols = hole_rows[hr]
                    for sc in range(shape_w):
                        gc = col_off + sc
                        if sr[sc] != 0:
                            if gc not in hcols:
                                ok = False
                                break
                        else:
                            if gc in hcols:
                                ok = False
                                break
                    if not ok:
                        break
                if ok:
                    grid_row_top = sorted_hr[-1]
                    return {'direction': direction, 'col_off': col_off, 'grid_row_top': grid_row_top}
            return None

    # Try matching each chain to each compatible hole
    placements = []
    used_holes = set()

    for chain in all_chains:
        shapes = [objects[i]['shape'] for i in chain]
        best = None
        for hi, hole in enumerate(holes):
            if hi in used_holes:
                continue
            for direction in ['top', 'bottom']:
                if direction == 'top' and hole['side'] not in ('top', 'both'):
                    continue
                if direction == 'bottom' and hole['side'] not in ('bottom', 'both'):
                    continue
                result = try_match_chain(chain, direction, hole)
                if result:
                    best = (hi, result)
                    break
            if best:
                break
        if best:
            hi, result = best
            used_holes.add(hi)
            placements.append((chain, result))

    # Build output
    output = [[0]*W for _ in range(H)]

    # Copy wall
    for r,c in wall_cells:
        output[r][c] = wall_color

    # Place chains
    for chain, placement in placements:
        shapes = [objects[i]['shape'] for i in chain]
        direction = placement['direction']
        col_off = placement['col_off']
        grid_row_top = placement['grid_row_top']

        # Compute overlaps
        overlaps = []
        for k in range(len(shapes)-1):
            overlaps.append(find_overlap(shapes[k], shapes[k+1]))

        if direction == 'top':
            # Shapes go from wall outward (upward)
            # First shape's bottom is closest to wall
            # Place first shape at grid_row_top
            current_row = grid_row_top
            for si, shape in enumerate(shapes):
                for r_off in range(len(shape)):
                    gr = current_row + r_off
                    for c_off in range(len(shape[0])):
                        gc = col_off + c_off
                        if 0 <= gr < H and 0 <= gc < W:
                            if shape[r_off][c_off] != 0 and output[gr][gc] == 0:
                                output[gr][gc] = shape[r_off][c_off]
                if si < len(overlaps):
                    current_row += len(shape) - overlaps[si]

        else:  # bottom
            # Shapes go from wall outward (downward)
            # Last shape's top is closest to wall (it's the entry shape)
            # Build from last to first
            # Entry shape is shapes[-1], placed with its top at grid_row_top

            # Compute starting row for each shape
            row_starts = [0] * len(shapes)
            # Last shape starts at grid_row_top
            row_starts[-1] = grid_row_top
            for si in range(len(shapes)-2, -1, -1):
                ov = overlaps[si]
                row_starts[si] = row_starts[si+1] - (len(shapes[si]) - ov)

            for si, shape in enumerate(shapes):
                for r_off in range(len(shape)):
                    gr = row_starts[si] + r_off
                    for c_off in range(len(shape[0])):
                        gc = col_off + c_off
                        if 0 <= gr < H and 0 <= gc < W:
                            if shape[r_off][c_off] != 0 and output[gr][gc] == 0:
                                output[gr][gc] = shape[r_off][c_off]

    if transposed:
        output = [list(row) for row in zip(*output)]

    return output

# Test on training examples
