    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    if not match:
        diff_count = sum(1 for r in range(len(expected)) for c in range(len(expected[0])) if result[r][c] != expected[r][c])
        print(f"Example {i}: FAIL ({diff_count} diffs)")
        # Show some diffs
        for r in range(len(expected)):
            for c in range(len(expected[0])):
                if result[r][c] != expected[r][c]:
                    print(f"  ({r},{c}): got {result[r][c]}, expected {expected[r][c]}")
                    break
    else:
        print(f"Example {i}: PASS")

